# @cctt_verify {"v":2,"sym":"sympy.functions.combinatorial.tests.test_comb_factorials.test_binomial_diff","kind":"function","src_hash":"642e58a02f48745e","in":{"base":"Any"},"out":{"base":"Any"},"spec":{"lhs":"test_binomial_diff()","rhs":"test_binomial_diff produces the expected output","over":{"base":"Any"},"name":"test_binomial_diff_correct"},"guarantee":"test_binomial_diff produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.functions.combinatorial.tests.test_comb_factorials.test_binomial_diff_correct","statement":"Path(test_binomial_diff(x), test_binomial_diff produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"11c6738078986d36"}
def test_binomial_diff():
    n = Symbol('n', integer=True)
    k = Symbol('k', integer=True)

    assert binomial(n, k).diff(n) == \
        (-polygamma(0, 1 + n - k) + polygamma(0, 1 + n))*binomial(n, k)
    assert binomial(n**2, k**3).diff(n) == \
        2*n*(-polygamma(
            0, 1 + n**2 - k**3) + polygamma(0, 1 + n**2))*binomial(n**2, k**3)

    assert binomial(n, k).diff(k) == \
        (-polygamma(0, 1 + k) + polygamma(0, 1 + n - k))*binomial(n, k)
    assert binomial(n**2, k**3).diff(k) == \
        3*k**2*(-polygamma(
            0, 1 + k**3) + polygamma(0, 1 + n**2 - k**3))*binomial(n**2, k**3)
    raises(ArgumentIndexError, lambda: binomial(n, k).fdiff(3))


